public class NestedIf {
  public static void main(String[] args) {
    int age = 25;
    boolean hasLicense = true;
    if (age >= 18) {
      if (hasLicense) {
        System.out.println("Sən maşın sürə bilərsən!");
      } else {
        System.out.println("Sürücülük vəsiqən yoxdur!");
      }
    } else {
      System.out.println("Sən yetkin deyilsən!");
    }
  }
}
// Çıxış: Sən maşın sürə bilərsən!

public class LogicalIf {
  public static void main(String[] args) {
    int age = 20;
    boolean isStudent = true;
    if (age >= 18 && isStudent) {
      System.out.println("Sən tələbə endirimi ala bilərsən!");
    } else if (age >= 18 && !isStudent) {
      System.out.println("Endirim yoxdur, amma yetkinsən!");
    } else {
      System.out.println("Heç bir endirim yoxdur!");
    }
  }
}
// Çıxış: Sən tələbə endirimi ala bilərsən!

public class DiscountSystem {
  public static void main(String[] args) {
    double totalAmount = 250.0;
    boolean isMember = true;
    double discount = 0.0;
    if (totalAmount >= 200 && isMember) {
      discount = totalAmount * 0.15; // 15% endirim
      System.out.println("Endirim: " + discount);
    } else if (totalAmount >= 100) {
      discount = totalAmount * 0.05; // 5% endirim
      System.out.println("Endirim: " + discount);
    } else {
      System.out.println("Endirim yoxdur.");
    }
    System.out.println("Yekun məbləğ: " + (totalAmount - discount));
  }
}
// Çıxış: Endirim: 37.5
// Yekun məbləğ: 212.5

